     2→import type { OrderDetailDataDto, getOrderDetailApi } from '../api/orderDetail.api';
     3→
     4→function getTransactionFromOrderDetail(dto: OrderDetailDataDto): PointsTransaction {
     5→  const items = dto.items || [];
     6→  const benefits = dto.benefits || [];
     7→
     8→  const totalValue = items.reduce((sum, item) => sum + (item.unitaryValue * item.quantity), 0);
     9→
    10→  const fields: Array<{ label: string; value: string }> = [];
    11→
    12→  if (items.length > 0) {
    13→    items.forEach((item, index) => {
    14→      fields.push({
    15→        label: `Item ${index + 1}`,
    16→        value: `${item.description} - ${item.quantity}x R$ ${item.unitaryValue.toFixed(2)}`,
    17→      });
    18→    });
    19→  }
    20→
    21→  if (benefits.length > 0) {
    22→    benefits.forEach((benefit, index) => {
    23→      fields.push({
    24→        label: `Benefício ${index + 1}`,
    25→        value: `${benefit.description} - R$ ${Math.abs(benefit.value).toFixed(2)}`,
    26→      });
    27→    });
    28→  }
    29→
    30→  return {
    31→    id: dto.id,
    32→    date: dto.date,
    33→    description: dto.description,
    34→    type: 'RESCUE',
    35→    amount: dto.amount,
    36→    currencyValue: totalValue > 0 ? totalValue : Math.abs(dto.amount),
    37→    icon: 'icon-cashback',
    38→    details: {
    39→      provider: 'Cashback',
    40→      extraInfo: '',
    41→      fields,
    42→    },
    43→    status: '',
    44→    marketplace: dto.marketplace,
    45→  };
    46→}
    47→
    48→export function getOrderDetailFromResponse(
    49→  response: Awaited<ReturnType<typeof getOrderDetailApi>>,
    50→): PointsTransaction | null {
    51→  const apiResponse = response?.data;
    52→
    53→  if (!apiResponse) {
    54→    return null;
    55→  }
    56→
    57→  const status = apiResponse.status;
    58→  const returnCode = status?.returnCode;
    59→
    60→  if (returnCode !== 200 && returnCode !== 0) {
    61→    return null;
    62→  }
    63→
    64→  const orderDetailData = apiResponse.data;
    65→
    66→  if (!orderDetailData) {
    67→    return null;
    68→  }
    69→
    70→  return getTransactionFromOrderDetail(orderDetailData);
    71→}
