     1→import { eventServerResponse } from '~/constants/functions';
     2→import { useRootStore } from '~/store';
     3→import {
     4→  getPointsBalanceApi,
     5→  getPointsExtractApi,
     6→  type ExtractRequestDto,
     7→} from '../api';
     8→import { ANALYTICS_EVENTS, EXTRACT_CONSTANTS } from '../constants';
     9→import {
    10→  PointsBalanceStatus,
    11→  PointsExtractStatus,
    12→  type PointsExtractData,
    13→} from '../models';
    14→import {
    15→  getPointsExtractFromResponse,
    16→  processPointsExtractData,
    17→} from '../repository';
    18→import { getParticipantIdFromToken } from '../utils';
    19→
    20→interface GetPointsExtractPayload {
    21→  page?: number;
    22→  type?: ExtractRequestDto['type'];
    23→  participantId?: string;
    24→}
    25→
    26→function shouldFetchExtract(
    27→  status: PointsExtractStatus,
    28→  isFirstPage: boolean,
    29→): boolean {
    30→  if (isFirstPage) {
    31→    return (
    32→      status !== PointsExtractStatus.LOADING &&
    33→      status !== PointsExtractStatus.SUCCESS
    34→    );
    35→  }
    36→  return true;
    37→}
    38→
    39→function handleExtractSuccess(
    40→  extractData: PointsExtractData,
    41→  processedData: ReturnType<typeof processPointsExtractData>,
    42→  isFirstPage: boolean,
    43→): void {
    44→  const { pointsExtractActions } = useRootStore.getState();
    45→
    46→  if (isFirstPage) {
    47→    pointsExtractActions.setExtractData(extractData, processedData);
    48→  } else {
    49→    pointsExtractActions.appendExtractData(extractData, processedData);
    50→  }
    51→
    52→  eventServerResponse(ANALYTICS_EVENTS.EXTRACT_SUCCESS);
    53→}
    54→
    55→function handleExtractError(isFirstPage: boolean): void {
    56→  const { pointsExtractActions } = useRootStore.getState();
    57→
    58→  if (isFirstPage) {
    59→    pointsExtractActions.setExtractStatus(PointsExtractStatus.ERROR);
    60→  } else {
    61→    pointsExtractActions.setLoadingMore(false);
    62→  }
    63→
    64→  eventServerResponse(ANALYTICS_EVENTS.EXTRACT_ERROR);
    65→}
    66→
    67→export async function getPointsExtract(
    68→  payload?: GetPointsExtractPayload,
    69→): Promise<void> {
    70→  const { pointsExtractActions, pointsExtract } = useRootStore.getState();
    71→
    72→  const page = payload?.page ?? EXTRACT_CONSTANTS.DEFAULT_PAGE;
    73→  const isFirstPage = page === EXTRACT_CONSTANTS.DEFAULT_PAGE;
    74→
    75→  if (!shouldFetchExtract(pointsExtract.status, isFirstPage)) {
    76→    return;
    77→  }
    78→
    79→  if (isFirstPage) {
    80→    pointsExtractActions.setExtractStatus(PointsExtractStatus.LOADING);
    81→  } else {
    82→    pointsExtractActions.setLoadingMore(true);
    83→  }
    84→
    85→  try {
    86→    const participantId =
    87→      payload?.participantId ?? (await getParticipantIdFromToken());
    88→
    89→    if (!participantId) {
    90→      handleExtractError(isFirstPage);
    91→      return;
    92→    }
    93→
    94→    const requestPayload: ExtractRequestDto = {
    95→      participantId,
    96→      page,
    97→      pageSize: EXTRACT_CONSTANTS.DEFAULT_PAGE_SIZE,
    98→      ...(payload?.type ? { type: payload.type } : {}),
    99→    };
   100→
   101→    const response = await getPointsExtractApi(requestPayload);
   102→    const extractData = getPointsExtractFromResponse(response);
   103→
   104→    if (extractData) {
   105→      const processedData = processPointsExtractData(extractData);
   106→      handleExtractSuccess(extractData, processedData, isFirstPage);
   107→      return;
   108→    }
   109→
   110→    handleExtractError(isFirstPage);
   111→  } catch {
   112→    handleExtractError(isFirstPage);
   113→  }
   114→}
   115→
   116→function shouldFetchBalance(status: PointsBalanceStatus): boolean {
   117→  return (
   118→    status !== PointsBalanceStatus.LOADING &&
   119→    status !== PointsBalanceStatus.SUCCESS
   120→  );
   121→}
   122→
   123→function handleBalanceSuccess(points?: number): void {
   124→  const { pointsExtractActions } = useRootStore.getState();
   125→  pointsExtractActions.setBalance(points);
   126→  eventServerResponse(ANALYTICS_EVENTS.BALANCE_SUCCESS);
   127→}
   128→
   129→function handleBalanceError(): void {
   130→  const { pointsExtractActions } = useRootStore.getState();
   131→  pointsExtractActions.setBalanceStatus(PointsBalanceStatus.ERROR);
   132→  eventServerResponse(ANALYTICS_EVENTS.BALANCE_ERROR);
   133→}
   134→
   135→export async function getPointsBalance(): Promise<void> {
   136→  const { pointsExtractActions, pointsBalance } = useRootStore.getState();
